INSERT INTO public.contenus_courants (id_courant, description_courte, caracteristiques_cles, contexte_historique, qcm_synthese)
VALUES
(1, $STR$PÃĐriode de renouveau artistique nÃĐe en Italie, caractÃĐrisÃĐe par la redÃĐcouverte de l'AntiquitÃĐ, le naturalisme et l'invention de la perspective linÃĐaire.$STR$, $JSON$["Perspective linÃĐaire","Humanisme","Naturalisme","Retour Ã  l'AntiquitÃĐ"]$JSON$::jsonb, $STR$Soutenue par de riches mÃĐcÃĻnes comme les MÃĐdicis Ã  Florence, cette ÃĐpoque marque la transition entre le Moyen Ãge et les temps modernes en Europe.$STR$, $JSON${"question":"Quelle grande innovation picturale caractÃĐrise la PremiÃĻre Renaissance en Italie ?","options":["L'invention de la perspective linÃĐaire mathÃĐmatique","L'utilisation exclusive de la peinture Ã  l'huile","L'abstraction gÃĐomÃĐtrique","Le pointillisme"],"correctIndex":0,"explanation":"FormalisÃĐe par Brunelleschi et Alberti, la perspective linÃĐaire a permis aux artistes de crÃĐer l'illusion d'un espace tridimensionnel profond sur une surface plane."}$JSON$::jsonb),
(2, $STR$L'apogÃĐe de l'art de la Renaissance, centrÃĐe sur Rome et Florence, dominÃĐe par les gÃĐnies universels comme LÃĐonard, Michel-Ange et RaphaÃŦl.$STR$, $JSON$["Sfumato et clair-obscur","Perspective parfaite","Proportions idÃĐales","Compositions pyramidales"]$JSON$::jsonb, $STR$MÃĐcÃĐnat papal trÃĻs puissant Ã  Rome, avec la construction de la nouvelle basilique Saint-Pierre et les fresques de la chapelle Sixtine.$STR$, $JSON${"question":"Quelle technique visuelle a ÃĐtÃĐ perfectionnÃĐe par LÃĐonard de Vinci pendant la Haute Renaissance ?","options":["Le Sfumato","Le TÃĐnÃĐbrisme","Le Cubisme","L'EmpÃĒtement"],"correctIndex":0,"explanation":"Le sfumato permet aux tons et aux couleurs de se fondre progressivement les uns dans les autres sans contours nets."}$JSON$::jsonb),
(3, $STR$Le pendant nordique (Flandres, Allemagne) de la Renaissance italienne, cÃĐlÃĻbre pour son rÃĐalisme minutieux et l'invention de la peinture Ã  l'huile.$STR$, $JSON$["RÃĐalisme minutieux","MaÃŪtrise de la peinture Ã  l'huile","Symbolisme cachÃĐ","Paysages dÃĐtaillÃĐs"]$JSON$::jsonb, $STR$Essor commercial des Flandres, dÃĐveloppement de l'imprimerie et prÃĐmices de la RÃĐforme protestante.$STR$, $JSON${"question":"Quelle technique picturale a ÃĐtÃĐ perfectionnÃĐe et popularisÃĐe par les maÃŪtres flamands comme Jan van Eyck ?","options":["La peinture Ã  l'huile","La fresque a fresco","La dÃĐtrempe Ã  l'Åuf","L'aquarelle"],"correctIndex":0,"explanation":"L'huile permet des glacis superposÃĐs, crÃĐant une profondeur et une luminositÃĐ inÃĐgalÃĐes pour le rendu des textures et de la lumiÃĻre."}$JSON$::jsonb),
(4, $STR$Un art thÃĐÃĒtral, dynamique et contrastÃĐ, conÃ§u pour susciter l'ÃĐmotion et l'ÃĐmerveillement, soutenu par l'Ãglise catholique.$STR$, $JSON$["Clair-obscur dramatique","Mouvement et diagonales","ThÃĐÃĒtralitÃĐ","AsymÃĐtrie"]$JSON$::jsonb, $STR$Art de la Contre-RÃĐforme, l'Ãglise catholique utilise l'art baroque pour ÃĐblouir et ramener les fidÃĻles face Ã  l'austÃĐritÃĐ protestante.$STR$, $JSON${"question":"Quel terme dÃĐsigne le fort contraste entre les zones de lumiÃĻre et d'ombre trÃĻs sombres caractÃĐristique du Baroque ?","options":["Le clair-obscur (TÃĐnÃĐbrisme)","L'estompage","Le sfumato","La grisaille"],"correctIndex":0,"explanation":"PopularisÃĐ par le Caravage, le tÃĐnÃĐbrisme isole violemment les figures illuminÃĐes sur un fond obscur."}$JSON$::jsonb),
(5, $STR$Une pÃĐriode de prospÃĐritÃĐ exceptionnelle aux Pays-Bas, donnant naissance Ã  de nouveaux genres profanes : paysages, natures mortes et scÃĻnes de genre.$STR$, $JSON$["ScÃĻnes de la vie quotidienne","Portraits bourgeois","Natures mortes","MaÃŪtrise de la lumiÃĻre"]$JSON$::jsonb, $STR$Les Provinces-Unies deviennent la premiÃĻre puissance commerciale mondiale; l'art est commandÃĐ par une riche bourgeoisie marchande.$STR$, $JSON${"question":"Qu'est-ce qui caractÃĐrise le plus les sujets de peinture de l'Ãge d'or nÃĐerlandais ?","options":["La vie quotidienne bourgeoise et laÃŊque","Les scÃĻnes bibliques monumentales","Les portraits de rois et de papes","L'abstraction pure"],"correctIndex":0,"explanation":"Pays protestant, les Pays-Bas ont dÃĐlaissÃĐ l'art religieux au profit des scÃĻnes de genre, paysages et natures mortes pour dÃĐcorer les maisons des riches marchands."}$JSON$::jsonb),
(6, $STR$Un mouvement exaltant les passions, l'individualisme, la puissance ÃĐcrasante de la nature et l'imagination face Ã  la rationalitÃĐ.$STR$, $JSON$["Exaltation des sentiments","Nature sublime et indomptable","Sujets dramatiques ou exotiques","Touches passionnÃĐes"]$JSON$::jsonb, $STR$RÃĐaction contre le rationalisme des LumiÃĻres et de la rÃĐvolution industrielle, et dÃĐsillusions post-RÃĐvolution franÃ§aise.$STR$, $JSON${"question":"Que cherchent principalement Ã  exprimer les peintres romantiques face Ã  la nature ?","options":["Le sublime et la toute-puissance des ÃĐlÃĐments","La gÃĐomÃĐtrie mathÃĐmatique","L'exactitude scientifique des plantes","La paix et l'ordre absolu"],"correctIndex":0,"explanation":"Le sublime romantique est un sentiment mÃŠlant terreur dÃĐlicieuse et admiration face Ã  l'immensitÃĐ terrifiante de la nature (tempÃŠtes, abÃŪmes, brumes)."}$JSON$::jsonb),
(7, $STR$La volontÃĐ de peindre la rÃĐalitÃĐ quotidienne et sociale sans l'idÃĐaliser, en s'intÃĐressant particuliÃĻrement au monde paysan et ouvrier.$STR$, $JSON$["Sujets de la vie ordinaire","Critique sociale","Refus de l'idÃĐalisation","Palette souvent sombre"]$JSON$::jsonb, $STR$RÃĐvolution industrielle en Europe, apparition du prolÃĐtariat urbain, et ÃĐvÃĐnements politiques comme la RÃĐvolution de 1848.$STR$, $JSON${"question":"Quel sujet devient noble et digne d'ÃŠtre peint en grand format avec l'apparition du RÃĐalisme ?","options":["Le travailleur et le paysan ordinaire","Les dieux de l'Olympe","Les rois de France","Les anges et les dÃĐmons"],"correctIndex":0,"explanation":"Gustave Courbet et les rÃĐalistes ont provoquÃĐ des scandales en peignant des paysans et des casseurs de pierres sur des toiles immenses, format jusqu'alors rÃĐservÃĐ Ã  la peinture d'histoire."}$JSON$::jsonb),
(8, $STR$Un mouvement cherchant Ã  capturer les effets optiques ÃĐphÃĐmÃĻres de la lumiÃĻre naturelle par des touches rapides et vibrantes en plein air.$STR$, $JSON$["Peinture en plein air","Touches visibles","Saisie de la lumiÃĻre instantanÃĐe","Couleurs claires et vives"]$JSON$::jsonb, $STR$DÃĐveloppement du chemin de fer, des loisirs modernes, invention des tubes de peinture et de la photographie.$STR$, $JSON${"question":"Quelle invention technologique a grandement favorisÃĐ l'essor de l'impressionnisme ?","options":["Le tube de peinture souple","Le pinceau en poils synthÃĐtiques","La toile en coton","L'ÃĐclairage ÃĐlectrique en atelier"],"correctIndex":0,"explanation":"Le tube de peinture en ÃĐtain a permis aux peintres de sortir facilement de leur atelier pour peindre la nature en direct ('en plein air')."}$JSON$::jsonb),
(9, $STR$Divers courants qui dÃĐpassent la simple impression visuelle pour structurer l'Åuvre (CÃĐzanne, Seurat) ou exprimer des ÃĐmotions intenses (Van Gogh, Gauguin).$STR$, $JSON$["Couleurs expressives ou scientifiques","ContrÃīle de la composition","Touche libÃĐrÃĐe et trÃĻs visible","Recherche de sens profond"]$JSON$::jsonb, $STR$Fin de siÃĻcle marquÃĐe par des avancÃĐes scientifiques en optique et une remise en question de la modernitÃĐ urbaine occidentale.$STR$, $JSON${"question":"Pourquoi parle-t-on de Post-Impressionnisme plutÃīt que d'un mouvement unifiÃĐ ?","options":["C'est un terme regroupant des artistes solitaires explorant des voies trÃĻs diffÃĐrentes au-delÃ  de l'impressionnisme","Parce qu'ils peignaient uniquement la nuit","Parce qu'ils copiaient tous Van Gogh","C'ÃĐtait le nom de leur galerie d'art"],"correctIndex":0,"explanation":"InventÃĐ a posteriori, le terme regroupe des recherches diverses : scientifiques (Seurat), gÃĐomÃĐtriques (CÃĐzanne), ou ÃĐmotionnelles (Van Gogh)."}$JSON$::jsonb),
(10, $STR$Mouvement visant Ã  projeter sur la toile la subjectivitÃĐ de l'artiste et son angoisse face au monde moderne, en dÃĐformant la rÃĐalitÃĐ.$STR$, $JSON$["DÃĐformation de la rÃĐalitÃĐ","Couleurs violentes et subjectives","Expression de l'angoisse et du malaise","Lignes torturÃĐes"]$JSON$::jsonb, $STR$Tensions prÃĐcÃĐdant la PremiÃĻre Guerre mondiale, crises morales et dures rÃĐalitÃĐs de l'industrialisation dans les grandes mÃĐtropoles, surtout en Allemagne.$STR$, $JSON${"question":"Quelle est l'intention principale de l'artiste expressionniste ?","options":["Projeter ses ÃĐmotions et angoisses intÃĐrieures en dÃĐformant le monde physique","Capturer avec exactitude la lumiÃĻre du soleil","Peindre avec une harmonie parfaite des proportions","Ne peindre que ce que l'Åil humain peut prouver scientifiquement"],"correctIndex":0,"explanation":"L'expressionnisme ne dÃĐcrit pas le monde tel qu'il est objectivement, mais tel que l'artiste le ressent, souvent de maniÃĻre tragique et dÃĐformÃĐe."}$JSON$::jsonb),
(11, $STR$Une rÃĐaction esthÃĐtique contre l'acadÃĐmisme, mÃŠlant onirisme, mysticisme et un goÃŧt pour l'ornementation florale stylisÃĐe.$STR$, $JSON$["Lignes courbes et vÃĐgÃĐtales","Mysticisme et rÃŠves","Ornementation dorÃĐe ou riche","Sujets allÃĐgoriques et mythologiques"]$JSON$::jsonb, $STR$PÃĐriode de la 'Belle Ãpoque' en Europe et Ã  Vienne, marquÃĐe par l'ÃĐmergence de la psychanalyse et un intÃĐrÃŠt pour l'occulte.$STR$, $JSON${"question":"Quelle caractÃĐristique visuelle est emblÃĐmatique de l'Art Nouveau ?","options":["La ligne courbe dite en 'coup de fouet', inspirÃĐe par la nature","L'utilisation stricte d'angles droits et de cubes","L'absence totale de motifs dÃĐcoratifs","La palette uniquement en noir et blanc"],"correctIndex":0,"explanation":"L'Art Nouveau s'inspire profondÃĐment de la biologie et de la botanique, utilisant des courbes ÃĐlÃĐgantes et dynamiques qui imitent des lianes ou des tiges florales."}$JSON$::jsonb),
(12, $STR$La plus grande rÃĐvolution picturale depuis la Renaissance : l'objet est fracturÃĐ, analysÃĐ et rÃĐassemblÃĐ sous une multitude d'angles simultanÃĐs.$STR$, $JSON$["MultiplicitÃĐ des points de vue","Formes gÃĐomÃĐtriques et facettes","Abandon de la perspective classique","Inclusion de vrais matÃĐriaux (collages)"]$JSON$::jsonb, $STR$Inventions technologiques (cinÃĐma, avions), dÃĐcouvertes de l'art tribal africain et ibÃĐrique influenÃ§ant les jeunes artistes Ã  Paris.$STR$, $JSON${"question":"Quel est l'objectif de la reprÃĐsentation cubiste d'un objet ?","options":["Le montrer sous plusieurs angles simultanÃĐment","Le rendre le plus photorÃĐaliste possible","Le rÃĐduire Ã  un simple trait de couleur pure","CrÃĐer une illusion d'optique en 3D (trompe-l'Åil)"],"correctIndex":0,"explanation":"PlutÃīt que de figer un objet d'un seul point de vue fixe, Picasso et Braque aplatissaient ses diffÃĐrentes faces (de face, de profil, de haut) sur une mÃŠme surface 2D."}$JSON$::jsonb),
(13, $STR$Exploration de l'inconscient, du rÃŠve et de l'irrationnel, libÃĐrant l'art de tout contrÃīle logique ou moral.$STR$, $JSON$["Associations d'objets illogiques","ScÃĻnes de rÃŠve (onirisme)","Automatisme","Hyper-rÃĐalisme pour un effet dÃĐroutant"]$JSON$::jsonb, $STR$Traumatisme de la PremiÃĻre Guerre mondiale, rejet du rationalisme qui y a menÃĐ, et forte influence des thÃĐories de Sigmund Freud sur l'inconscient.$STR$, $JSON${"question":"Quel thÃĐoricien et mÃĐdecin a profondÃĐment influencÃĐ le mouvement surrÃĐaliste ?","options":["Sigmund Freud et ses thÃĐories sur l'inconscient","Albert Einstein et la relativitÃĐ","Charles Darwin et l'ÃĐvolution","Karl Marx et le manifeste communiste"],"correctIndex":0,"explanation":"AndrÃĐ Breton et les surrÃĐalistes se sont passionnÃĐs pour l'inconscient, le rÃŠve et la psychanalyse de Freud pour libÃĐrer l'esprit crÃĐatif des contraintes logiques."}$JSON$::jsonb),
(14, $STR$Une peinture focalisÃĐe sur la rÃĐalitÃĐ quotidienne de la vie urbaine ou rurale amÃĐricaine, capturant l'isolation et la modernitÃĐ.$STR$, $JSON$["MÃĐlancolie et solitude urbaine","Sujets vernaculaires amÃĐricains","LumiÃĻres froides et cinÃĐmatographiques","ScÃĻnes figÃĐes"]$JSON$::jsonb, $STR$Grande DÃĐpression des annÃĐes 30, isolationnisme amÃĐricain et dÃĐveloppement frÃĐnÃĐtique des villes modernes.$STR$, $JSON${"question":"Quelle ÃĐmotion se dÃĐgage trÃĻs frÃĐquemment des toiles rÃĐalistes amÃĐricaines (comme celles de Hopper) ?","options":["La solitude, l'isolement et l'aliÃĐnation urbaine","La joie de vivre festive et frÃĐnÃĐtique","La terreur de la mort","L'extase religieuse mystique"],"correctIndex":0,"explanation":"Les Åuvres de Hopper ou de ses contemporains capturent souvent le sentiment paradoxal d'ÃŠtre seul au milieu de la grande ville moderne."}$JSON$::jsonb);
